from typing import List

def calculateMinimumHP(dungeon: List[List[int]]) -> int:
    R = len(dungeon)
    C = len(dungeon[0])

    dp = [[0] * C for _ in range(R)]

    for r in range(R - 1, -1, -1):
        for c in range(C - 1, -1, -1):
            if r == R - 1 and c == C - 1:
                dp[r][c] = max(1, 1 - dungeon[r][c])
            elif r == R - 1:
                dp[r][c] = max(1, dp[r][c+1] - dungeon[r][c])
            elif c == C - 1:
                dp[r][c] = max(1, dp[r+1][c] - dungeon[r][c])
            else:
                min_health_required_from_next_step = min(dp[r][c+1], dp[r+1][c])
                dp[r][c] = max(1, min_health_required_from_next_step - dungeon[r][c])

    return dp[0][0]
